    let (mut s, mut r) = (true, true);
    for i in 1..a.len() {
        if a[i-1] > a[i] { s = false }
        if a[i-1] < a[i] { r = false }
        if !s && !r { break }
    }
    if s { return }
    if r { a.reverse(); return }
    qs(a);
}

fn qs<T: Ord + Clone>(mut a: &mut [T]) {
    while a.len() > 24 {
        let p = {
            let (m, l) = (a.len() / 2, a.len() - 1);
            if a[0] > a[m] { a.swap(0, m) }
            if a[0] > a[l] { a.swap(0, l) }
            if a[m] > a[l] { a.swap(m, l) }
            a[m].clone()
        };
        let (mut lt, mut i, mut gt) = (0, 0, a.len());
        while i < gt {
            match a[i].cmp(&p) {
                Ordering::Less => { a.swap(lt, i); lt += 1; i += 1 }
                Ordering::Greater => { gt -= 1; a.swap(i, gt) }
                _ => i += 1
            }
        }
        let (left, rem) = a.split_at_mut(lt);
        let right = &mut rem[gt-lt..];
        if left.len() < right.len() { qs(left); a = right }
        else { qs(right); a = left }
    }
    is(a);
}

fn is<T: Ord>(a: &mut [T]) {
    for i in 1..a.len() {
        let mut j = i;
        while j > 0 && a[j-1] > a[j] { a.swap(j, j-1); j -= 1 }
